import{_ as l}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as e,e as i}from"./app-20545810.js";const s={},n=i(`<blockquote><p>SQL 첫걸음 1 ~ 5강의 내용입니다</p></blockquote><h2 id="데이터-베이스를-조작하는-언어-sql" tabindex="-1"><a class="header-anchor" href="#데이터-베이스를-조작하는-언어-sql" aria-hidden="true">#</a> 데이터 베이스를 조작하는 언어 SQL</h2><ul><li><p>SQL은 &#39;관계형 데이터베이스 관리 시스템(RDBMS)&#39;을 조작할 때 사용한다.</p></li><li><p>관계형 데이터베이스</p><ul><li>Oracle</li><li>DB2</li><li>SQL Server</li><li>PostgreSQL</li><li>MySQL</li><li>SQLite</li></ul></li></ul><h2 id="sql-명령의-종류" tabindex="-1"><a class="header-anchor" href="#sql-명령의-종류" aria-hidden="true">#</a> SQL 명령의 종류</h2><ul><li><p>SQL 명령은 크게 3가지로 나뉜다 (조작, 정의, 제어)</p><ul><li><p>DML(Data Manipulation Language)</p><ul><li>데이터베이스에 데이터를 추가, 삭제, 갱신 등 데이터를 조작할 때 사용</li></ul></li><li><p>DDL(Data Definition Language)</p><ul><li>데이터의 객체를 만들거나 삭제하는 명령어</li></ul></li><li><p>DCL(Data Control Language)</p><ul><li>데이터를 제어하는 명령어, 트랜잭션과 데이터 접근 권한을 제어</li></ul></li></ul><p>📌 트랜잭션에 관해서는 아래에서 설명</p></li></ul><h2 id="테이블-조회" tabindex="-1"><a class="header-anchor" href="#테이블-조회" aria-hidden="true">#</a> 테이블 조회</h2><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> 테이블명<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><p><code>SELECT</code>는 DML에 속하는 명령어. &#39;질의&#39;나 &#39;쿼리&#39;로 불리기도 함</p></li><li><p>&#39;*&#39;은 &#39;모든 열(Field)&#39;을 의미하는 메타문자</p></li><li><p>대소문자 구별</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">select</span> <span class="token operator">*</span> <span class="token keyword">from</span> sample21<span class="token punctuation">;</span>
<span class="token keyword">Select</span> <span class="token operator">*</span> <span class="token keyword">From</span> Sample21<span class="token punctuation">;</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> SAMPLE21<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>예약어와 객체명은 대소문자를 구별하지 않는다</li><li>책에서는 구분하기 쉽도록 예약어는 대문자, 객체명은 소문자로 표기</li></ul></li></ul><h2 id="테이블-구조-참조하기" tabindex="-1"><a class="header-anchor" href="#테이블-구조-참조하기" aria-hidden="true">#</a> 테이블 구조 참조하기</h2><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">DESC</span> 테이블명<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>DESC</code>는 SQL 명령이 아니다</li><li>테이블이 가진 열(Field)에 대한 자료형을 알 수 있음</li></ul><h3 id="자료형" tabindex="-1"><a class="header-anchor" href="#자료형" aria-hidden="true">#</a> 자료형</h3><ul><li><p>INTEGER(정수)형</p><ul><li>소수점 포함 불가</li></ul></li><li><p>CHAR(문자)형</p><ul><li>최대 길이 지정</li><li>지정된 길이 만큼 고정되어 저장</li><li>최대 길이 보다 작은 문자열의 경우 공백문자로 나머지를 채움</li></ul></li><li><p>VARCHAR(문자) 형</p><ul><li>&#39;가변 길이 문자열&#39; 자료형</li><li>데이터 크기에 맞춰 저장공간의 크기도 변경</li></ul></li><li><p>DATE 형</p><ul><li>연월일 데이터 저장</li></ul></li><li><p>TIME 형</p><ul><li>시분초 데이터 저장</li></ul></li></ul>`,13),p=[n];function d(o,r){return a(),e("div",null,p)}const u=l(s,[["render",d],["__file","sql.html.vue"]]);export{u as default};
